import{_ as e,c as t,o as a,a as o}from"./app.b609ccdd.js";const g='{"title":"Introduction","description":"","frontmatter":{},"headers":[{"level":2,"title":"Introduction","slug":"introduction"},{"level":3,"title":"What is Awesome Starter?","slug":"what-is-awesome-starter"},{"level":3,"title":"What is Create Preset?","slug":"what-is-create-preset"},{"level":3,"title":"Compatibility Note","slug":"compatibility-note"},{"level":2,"title":"Getting Started","slug":"getting-started"},{"level":3,"title":"Usage","slug":"usage"},{"level":3,"title":"Simply Usage","slug":"simply-usage"},{"level":2,"title":"More Features","slug":"more-features"},{"level":3,"title":"Full Documentation","slug":"full-documentation"},{"level":3,"title":"Template list","slug":"template-list"}],"relativePath":"guide.md"}',r={},s=o(`<h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-hidden="true">#</a></h2><p>Welcome to Awesome Starter!</p><h3 id="what-is-awesome-starter" tabindex="-1">What is Awesome Starter? <a class="header-anchor" href="#what-is-awesome-starter" aria-hidden="true">#</a></h3><p>Awesome Starter is a curated list of awesome things related to starter templates. Create some interesting and practical project startup templates through <a href="#what-is-create-preset">Create Preset CLI</a>, and it can also help you manage your favorite project configurations.</p><p>For a long time, there has been a lack of a tool to manage the configuration of your own public and private projects, so with the birth of Create Preset, if you find it useful, <a href="https://github.com/awesome-starter/create-preset" target="_blank" rel="noopener noreferrer">Welcome to give it a Star</a> !</p><h3 id="what-is-create-preset" tabindex="-1">What is Create Preset? <a class="header-anchor" href="#what-is-create-preset" aria-hidden="true">#</a></h3><p>The CLI for Awesome Starter, Provides the ability to quickly create preset projects.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>In addition to creating excellent templates provided by the official and open source communities, you are encouraged to use it as a tool for managing personal common project configurations, Visit <a href="./docs.html#manage-local-configuration">Manage local configuration</a> to learn more.</p></div><p><img src="https://cdn.jsdelivr.net/gh/chengpeiquan/assets-storage/img/2021/11/20220110155037.gif" alt=""></p><h3 id="compatibility-note" tabindex="-1">Compatibility Note <a class="header-anchor" href="#compatibility-note" aria-hidden="true">#</a></h3><p>Some preset project requires <a href="https://nodejs.org/en/" target="_blank" rel="noopener noreferrer">Node.js</a> version &gt;=12.2.0 (e.g. Vite). However, some templates require a higher Node.js version to work, please upgrade if your package manager warns about it.</p><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-hidden="true">#</a></h2><p>We provide two ways to use this CLI.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Since <code>v0.6.0</code>, the documentation will explain the operation instructions in the form of global installation by default. Of course, you can still quickly experience it through the package manager commands.</p></div><h3 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-hidden="true">#</a></h3><p>It is recommended to install globally for easier usage, Please install it globally first:</p><div class="language-bash"><pre><code><span class="token function">npm</span> <span class="token function">install</span> -g create-preset
</code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If you encounter an error of <code>node:internal/readline/emitKeypressEvents:71</code> when installing globally, please refer to the solution of <a href="https://github.com/awesome-starter/create-preset/issues/29" target="_blank" rel="noopener noreferrer">#29</a> .</p></div><p>You can use the following command to check whether the installation was successful. If successful, you will get a version number.</p><div class="language-bash"><pre><code><span class="token comment"># View the version number of the global installation</span>
preset -v
</code></pre></div><p>Then you can create a project by &quot;Select Technology Stack -&gt; Select Template&quot;:</p><div class="language-bash"><pre><code><span class="token comment"># It will start &quot;Select Technology Stack -&gt; Select Template&quot;</span>
preset init
</code></pre></div><p>You can also directly specify a template to create a project (requires <code>v0.12.0</code> above):</p><div class="language-bash"><pre><code><span class="token comment"># A project called \`hello-vue\` will be created using the \`vue3-ts-vite\` template</span>
preset init hello-vue --template vue3-ts-vite
</code></pre></div><p>You can refer to <a href="#upgrade">Upgrade</a> to learn how to upgrade in the future.</p><h3 id="simply-usage" tabindex="-1">Simply Usage <a class="header-anchor" href="#simply-usage" aria-hidden="true">#</a></h3><p>You can also simply experience it through the command of the package manager, and directly create the template you need by create preset.</p><div class="language-bash"><pre><code><span class="token function">npm</span> create preset
</code></pre></div><p>Then follow the prompts!</p><p>This usage allows you to use the latest version of the Preset CLI every time.</p><h2 id="more-features" tabindex="-1">More Features <a class="header-anchor" href="#more-features" aria-hidden="true">#</a></h2><h3 id="full-documentation" tabindex="-1">Full Documentation <a class="header-anchor" href="#full-documentation" aria-hidden="true">#</a></h3><p>Please visit <a href="/docs.html">Documentation</a> for more features.</p><h3 id="template-list" tabindex="-1">Template list <a class="header-anchor" href="#template-list" aria-hidden="true">#</a></h3><p>There are already some available templates, and the official website will open up a list of templates to provide inquiries later, so stay tuned!</p>`,35),i=[s];function l(n,c,p,d,h,u){return a(),t("div",null,i)}var f=e(r,[["render",l]]);export{g as __pageData,f as default};
